
const baseApiEndpoint = 'https://api.sadiq.us.to';
const applicationKey = 'YWNlYmI5Mzk0NTEwNDA2ZTgzYTUwODI4MDY3OTVkMTI=';

async function retrieveToken() {
  let token = '';
  if (typeof localStorage != 'undefined' && typeof window != 'undefined') {
    if (localStorage.getItem('token')) {
      try {
        token = localStorage.getItem('token');
        token = JSON.parse(token);
        if (new Date(token.expiration) >= new Date()) {
          return token.token;
        }
        localStorage.removeItem('token');
      } catch (e) {
        console.error(e);
      }

    }

    try {
      const response = await fetch(baseApiEndpoint + '/token/create', {
        method: "POST",
        mode: "cors",
        cache: "no-cache",
        headers: {
          "X-App-Key": window.atob(applicationKey),
          "Content-Type": "application/json"
        },
        redirect: "follow",
        referrerPolicy: "no-referrer"
      });

      const data = await response.json(); // Parse response as JSON
      if (data && data.token) {
        localStorage.setItem('token', JSON.stringify(data)); // Store token string in local storage
        return data.token; // Return token string
      } else {
        throw new Error('Token not found in response');
      }
    } catch (error) {
      console.error('Error fetching token:', error);
      return '';
    }
  }
  return token;
}

retrieveToken().then(token => {

  token = token.toString();

  // Visitor record API
  let metaInfo = {};
  if (typeof screen != 'undefined') {
    metaInfo['referer'] = document.referrer;
    metaInfo['screen'] = {
      width: screen.width,
      height: screen.height,
      colorDepth: screen.colorDepth,
      pixelDepth: screen.pixelDepth
    };
  }
  if (typeof navigator != 'undefined') {
    for (let i in navigator) {
      metaInfo[i] = navigator[i];
    }
  }
  fetch(baseApiEndpoint + '/log/visitor', {
    method: "POST",
    mode: "cors",
    cache: "no-cache",
    headers: {
      "X-Auth": token,
      "Content-Type": "application/json"
    },
    redirect: "follow",
    referrerPolicy: "no-referrer",
    body: JSON.stringify({
      meta: metaInfo
    }),
  });

});



